<script lang="ts">
  import { page } from '$app/state';import { Columns3, FileText } from '@lucide/svelte';import { api } from '$lib/api';import SettingsPanel from '$lib/SettingsPanel.svelte';import SubtitleReview from '$lib/SubtitleReview.svelte';
  const sessionId=String(page.params.id);let documents=$state<any[]>([]);let review=$state(false);let sourceArtifact=$state('');
  async function load(){documents=(await api<{items:any[]}>(`/sessions/${sessionId}/documents`)).items;const artifacts=await api<{items:any[]}>(`/artifacts?session_id=${sessionId}&limit=100`);sourceArtifact=artifacts.items.find((item:any)=>item.role==='upload')?.id??''}load();
</script>
<div class="space-y-5"><div class="flex flex-wrap items-end justify-between gap-4"><div><h2 class="text-2xl font-semibold">Text and subtitles</h2><p class="muted mt-2">Correction creates a same-language asset; translation and TTS optimization remain independent transformations.</p></div><button onclick={()=>review=true} disabled={!documents.some((item)=>['transcription','correction','translation'].includes(item.stage))} class="flex items-center gap-2 rounded-xl bg-[var(--accent)] px-4 py-2.5 text-sm font-semibold text-white disabled:opacity-40"><Columns3 size={16}/> Compare subtitles</button></div><section class="surface rounded-2xl p-5"><div class="eyebrow">Document history</div><div class="mt-4 grid gap-3 md:grid-cols-2">{#each documents as document}<article class="rounded-xl border border-[var(--line)] p-4"><div class="flex items-center gap-3"><FileText class="text-[var(--accent)]" size={18}/><div><div class="font-semibold capitalize">{document.stage.replaceAll('_',' ')}</div><div class="muted text-xs">{document.revisions.length} revision(s) · {document.language??'language unspecified'}</div></div></div></article>{:else}<p class="muted text-sm">Process a source to create the first document revision.</p>{/each}</div></section><SettingsPanel {sessionId} section="text" title="Text processing"/><SettingsPanel {sessionId} section="stt" title="Speech recognition and VAD"/><SettingsPanel {sessionId} section="subtitles" title="Subtitle composition" description="Viewer-facing cue limits are independent from dubbing speech blocks."/><SettingsPanel {sessionId} section="correction" title="Subtitle correction" description="Creates a same-language revision intended to be proper subtitles."/><SettingsPanel {sessionId} section="translation" title="Translation" description="May translate directly from source or from a corrected revision."/></div>{#if review}<SubtitleReview {sessionId} sourceArtifactId={sourceArtifact} onclose={()=>review=false} onsaved={load}/>{/if}
